const scene = document.getElementById("scene");
const W = () => window.innerWidth;
const H = () => window.innerHeight;
const crossY = () => H() * 0.5;
const crossHalf = 55;
const stopGap = 26;

const laneXs = [W() * 0.415, W() * 0.463, W() * 0.537, W() * 0.585];

const vehicles = [];
const people = [];

let verticalPower = 0;
let horizontalPower = 0;
let crossingMode = false;
let lastMouseX = W() / 2;
let lastMouseY = H() / 2;
let lastMoveTime = performance.now();

function createVehicle(type, laneIndex, y, speed, cls) {
	const el = document.createElement("div");
	el.className = `vehicle ${type} ${cls}`;
	el.innerHTML = `
      <div class="body"></div>
      <div class="roof"></div>
      <div class="windowTop"></div>
      <div class="windowBottom"></div>
      <div class="wheel w1"></div>
      <div class="wheel w2"></div>
      <div class="wheel w3"></div>
      <div class="wheel w4"></div>
    `;
	scene.appendChild(el);

	const direction = laneIndex < 2 ? -1 : 1;
	const h = type === "bus" ? 88 : 64;

	const vehicle = {
		el,
		laneIndex,
		x: laneXs[laneIndex],
		y,
		baseSpeed: speed * direction,
		currentSpeed: speed * direction,
		w: type === "bus" ? 42 : 36,
		h,
		waiting: false
	};

	vehicles.push(vehicle);
	return vehicle;
}

function createPerson(side, offset, palette) {
	const el = document.createElement("div");
	el.className = "person";
	el.innerHTML = `
      <div class="head"></div>
      <div class="body"></div>
      <div class="legs"></div>
    `;
	el.querySelector(".body").style.background = palette;
	scene.appendChild(el);

	const p = {
		el,
		side,
		row: offset,
		x:
			side === "left"
				? W() * 0.39 - 70 - offset * 18
				: W() * 0.61 + 70 + offset * 18,
		y: crossY() + ((offset % 3) - 1) * 16,
		targetX: 0,
		speed: 0,
		phase: Math.random() * Math.PI * 2
	};

	people.push(p);
	return p;
}

function resetPeopleTargets() {
	people.forEach((p) => {
		p.targetX = crossingMode
			? p.side === "left"
				? W() * 0.61 + 70
				: W() * 0.39 - 70
			: p.side === "left"
			? W() * 0.39 - 70
			: W() * 0.61 + 70;

		p.speed = 1.1 + Math.random() * 0.7;
	});
}

function init() {
	createVehicle("car", 0, H() * 0.18, 1.8, "car1");
	createVehicle("bus", 1, H() * 0.48, 1.2, "bus");
	createVehicle("car", 0, H() * 0.78, 1.6, "car2");
	createVehicle("car", 1, H() * 0.92, 1.9, "car3");
	createVehicle("bus", 2, H() * 0.16, 1.05, "bus");
	createVehicle("car", 3, H() * 0.35, 1.7, "car4");
	createVehicle("car", 2, H() * 0.68, 1.5, "car2");
	createVehicle("car", 3, H() * 0.88, 1.85, "car1");

	createPerson("left", 0, "#6a5cff");
	createPerson("left", 1, "#ff6b6b");
	createPerson("left", 2, "#ffd84d");
	createPerson("right", 0, "#00c2a8");
	createPerson("right", 1, "#ff8c42");
	createPerson("right", 2, "#8d6bff");

	resetPeopleTargets();
}

function applyPositions() {
	vehicles.forEach((v) => {
		v.x = laneXs[v.laneIndex];
		v.el.style.left = `${v.x}px`;
		v.el.style.top = `${v.y}px`;
	});

	people.forEach((p) => {
		p.el.style.left = `${p.x}px`;
		p.el.style.top = `${
			p.y + Math.sin(performance.now() * 0.01 + p.phase) * 0.6
		}px`;
	});
}

function resizeAll() {
	laneXs[0] = W() * 0.415;
	laneXs[1] = W() * 0.463;
	laneXs[2] = W() * 0.537;
	laneXs[3] = W() * 0.585;

	people.forEach((p, i) => {
		if (!crossingMode) {
			p.x =
				p.side === "left"
					? W() * 0.39 - 70 - (i % 3) * 18
					: W() * 0.61 + 70 + (i % 3) * 18;
		}
		p.y = crossY() + ((i % 3) - 1) * 16;
	});

	applyPositions();
}

function getStopLine(v) {
	if (v.baseSpeed < 0) {
		return crossY() + crossHalf + stopGap + v.h / 2;
	}
	return crossY() - crossHalf - stopGap - v.h / 2;
}

function vehicleWouldEnterCrosswalk(v, nextY) {
	const front = nextY + (v.baseSpeed < 0 ? -v.h / 2 : v.h / 2);
	const crossTop = crossY() - crossHalf;
	const crossBottom = crossY() + crossHalf;

	if (v.baseSpeed < 0) {
		return front <= crossBottom && v.y > crossBottom;
	}

	return front >= crossTop && v.y < crossTop;
}

function updateVehicles() {
	vehicles.forEach((v) => {
		if (crossingMode) {
			const stopLine = getStopLine(v);
			const desired = 0;

			if (v.baseSpeed < 0) {
				if (v.y <= stopLine) {
					v.waiting = true;
					v.y = stopLine;
					v.currentSpeed += (desired - v.currentSpeed) * 0.22;
					v.currentSpeed = 0;
				} else {
					v.waiting = false;
					const slowTarget = Math.max(v.baseSpeed * 0.9, -2.2);
					v.currentSpeed += (slowTarget - v.currentSpeed) * 0.08;
					const nextY = v.y + v.currentSpeed;
					if (vehicleWouldEnterCrosswalk(v, nextY)) {
						v.y = stopLine;
						v.currentSpeed = 0;
						v.waiting = true;
					} else {
						v.y = nextY;
					}
				}
			} else {
				if (v.y >= stopLine) {
					v.waiting = true;
					v.y = stopLine;
					v.currentSpeed += (desired - v.currentSpeed) * 0.22;
					v.currentSpeed = 0;
				} else {
					v.waiting = false;
					const slowTarget = Math.min(v.baseSpeed * 0.9, 2.2);
					v.currentSpeed += (slowTarget - v.currentSpeed) * 0.08;
					const nextY = v.y + v.currentSpeed;
					if (vehicleWouldEnterCrosswalk(v, nextY)) {
						v.y = stopLine;
						v.currentSpeed = 0;
						v.waiting = true;
					} else {
						v.y = nextY;
					}
				}
			}
		} else {
			v.waiting = false;
			const extra = verticalPower * 4;
			const target = v.baseSpeed + extra;
			v.currentSpeed += (target - v.currentSpeed) * 0.08;
			v.y += v.currentSpeed;
		}

		if (!crossingMode) {
			if (v.currentSpeed < 0 && v.y < -120) v.y = H() + 120;
			if (v.currentSpeed > 0 && v.y > H() + 120) v.y = -120;
		} else {
			if (v.baseSpeed < 0 && v.y < -120) v.y = H() + 120;
			if (v.baseSpeed > 0 && v.y > H() + 120) v.y = -120;
		}
	});
}

function updatePeople() {
	people.forEach((p, i) => {
		const dx = p.targetX - p.x;

		if (Math.abs(dx) > 1) {
			p.x += Math.sign(dx) * p.speed;
		}

		if (crossingMode) {
			const offsetY = ((i % 3) - 1) * 16;
			p.y += (crossY() + offsetY - p.y) * 0.12;
		} else {
			const homeY = crossY() + ((i % 3) - 1) * 16;
			p.y += (homeY - p.y) * 0.08;
		}
	});
}

scene.addEventListener("mousemove", (e) => {
	const now = performance.now();
	const dx = e.clientX - lastMouseX;
	const dy = e.clientY - lastMouseY;
	const dt = Math.max(16, now - lastMoveTime);

	horizontalPower = Math.max(-1, Math.min(1, (dx / dt) * 9));
	verticalPower = Math.max(-1, Math.min(1, (dy / dt) * 9));

	const nextCrossingMode =
		Math.abs(horizontalPower) > Math.abs(verticalPower) &&
		Math.abs(horizontalPower) > 0.12;

	if (nextCrossingMode !== crossingMode) {
		crossingMode = nextCrossingMode;
		resetPeopleTargets();
	}

	lastMouseX = e.clientX;
	lastMouseY = e.clientY;
	lastMoveTime = now;
});

scene.addEventListener("mouseleave", () => {
	verticalPower = 0;
	horizontalPower = 0;
	crossingMode = false;
	resetPeopleTargets();
});

function loop() {
	updateVehicles();
	updatePeople();
	applyPositions();
	requestAnimationFrame(loop);
}

init();
resizeAll();
loop();

window.addEventListener("resize", resizeAll);

style.css:
* {
	box-sizing: border-box;
}

html,
body {
	margin: 0;
	height: 100%;
	overflow: hidden;
	background: #7ec850;
	font-family: monospace;
	image-rendering: pixelated;
	cursor: crosshair;
}

.scene {
	position: relative;
	width: 100vw;
	height: 100vh;
	overflow: hidden;
	background: linear-gradient(
		to right,
		#6fb648 0 18%,
		#81cf57 18% 22%,
		#6fb648 22% 39%,
		#2e2e2e 39% 61%,
		#6fb648 61% 78%,
		#81cf57 78% 82%,
		#6fb648 82% 100%
	);
}

.road {
	position: absolute;
	left: 39%;
	width: 22%;
	top: 0;
	bottom: 0;
	background: linear-gradient(
		to right,
		#202020 0 2%,
		#2f2f2f 2% 24.5%,
		#d8d8d8 24.5% 25.5%,
		#2f2f2f 25.5% 49.5%,
		#f5c542 49.5% 50.5%,
		#2f2f2f 50.5% 74.5%,
		#d8d8d8 74.5% 75.5%,
		#2f2f2f 75.5% 98%,
		#202020 98% 100%
	);
	box-shadow: inset 0 0 0 4px #1b1b1b;
}

.laneMarkings {
	position: absolute;
	inset: 0;
	pointer-events: none;
}

.laneMarkings::before,
.laneMarkings::after {
	content: "";
	position: absolute;
	top: -200px;
	bottom: -200px;
	width: 6px;
	background: repeating-linear-gradient(
		to bottom,
		#f7f7f7 0 24px,
		transparent 24px 48px
	);
	opacity: 0.9;
}

.laneMarkings::before {
	left: 25%;
	transform: translateX(-50%);
}

.laneMarkings::after {
	left: 75%;
	transform: translateX(-50%);
}

.medianDash {
	position: absolute;
	left: 50%;
	top: -200px;
	bottom: -200px;
	width: 8px;
	transform: translateX(-50%);
	background: repeating-linear-gradient(
		to bottom,
		#f2c94c 0 18px,
		transparent 18px 36px
	);
	opacity: 0.95;
	pointer-events: none;
}

.crosswalkZone {
	position: absolute;
	left: 39%;
	width: 22%;
	top: 50%;
	height: 110px;
	transform: translateY(-50%);
	pointer-events: none;
}

.crosswalkRoad {
	position: absolute;
	inset: 0;
	background: repeating-linear-gradient(
		to right,
		#f4f4f4 0 10px,
		transparent 10px 20px
	);
	opacity: 0.9;
}

.crosswalkGrass {
	position: absolute;
	left: -220px;
	right: -220px;
	top: 34px;
	height: 42px;
	background: linear-gradient(
		to bottom,
		transparent 0 6px,
		#ececec 6px 36px,
		transparent 36px 100%
	);
	opacity: 0.95;
}

.dividerLine {
	position: absolute;
	left: 0;
	right: 0;
	top: 50%;
	height: 2px;
	background: #1b1b1b;
	transform: translateY(-50%);
	opacity: 0.25;
}

.sidewalkLeft,
.sidewalkRight {
	position: absolute;
	top: 50%;
	width: 180px;
	height: 52px;
	transform: translateY(-50%);
	background: linear-gradient(
		to bottom,
		#b9b9b9 0 8px,
		#d6d6d6 8px 44px,
		#a6a6a6 44px 100%
	);
	box-shadow: inset 0 0 0 3px #8c8c8c;
}

.sidewalkLeft {
	right: 100%;
}

.sidewalkRight {
	left: 100%;
}

.vehicle {
	position: absolute;
	width: 36px;
	height: 64px;
	transform: translate(-50%, -50%);
	z-index: 4;
}

.vehicle.bus {
	width: 42px;
	height: 88px;
}

.vehicle .body {
	position: absolute;
	inset: 0;
	box-shadow: inset 0 0 0 4px rgba(0, 0, 0, 0.35);
}

.vehicle.car1 .body {
	background: #ff5d5d;
}
.vehicle.car2 .body {
	background: #5da8ff;
}
.vehicle.car3 .body {
	background: #ffd84d;
}
.vehicle.car4 .body {
	background: #7dff7d;
}
.vehicle.bus .body {
	background: #ff8c42;
}

.vehicle .roof {
	position: absolute;
	left: 7px;
	right: 7px;
	top: 12px;
	bottom: 12px;
	background: #d9f1ff;
	box-shadow: inset 0 0 0 4px rgba(0, 0, 0, 0.25);
}

.vehicle.bus .roof {
	left: 6px;
	right: 6px;
	top: 14px;
	bottom: 14px;
}

.vehicle .windowTop,
.vehicle .windowBottom {
	position: absolute;
	left: 9px;
	right: 9px;
	height: 10px;
	background: #cfeeff;
}

.vehicle .windowTop {
	top: 8px;
}
.vehicle .windowBottom {
	bottom: 8px;
}

.vehicle.bus .windowTop,
.vehicle.bus .windowBottom {
	left: 6px;
	right: 6px;
	height: 12px;
}

.vehicle .wheel {
	position: absolute;
	width: 6px;
	height: 12px;
	background: #111;
}

.vehicle .wheel.w1 {
	left: -2px;
	top: 10px;
}
.vehicle .wheel.w2 {
	right: -2px;
	top: 10px;
}
.vehicle .wheel.w3 {
	left: -2px;
	bottom: 10px;
}
.vehicle .wheel.w4 {
	right: -2px;
	bottom: 10px;
}

.vehicle.bus .wheel {
	width: 7px;
	height: 14px;
}

.person {
	position: absolute;
	width: 14px;
	height: 22px;
	transform: translate(-50%, -50%);
	z-index: 6;
}

.person .head {
	position: absolute;
	top: 0;
	left: 3px;
	width: 8px;
	height: 8px;
	background: #f2c29b;
}

.person .body {
	position: absolute;
	top: 8px;
	left: 2px;
	width: 10px;
	height: 8px;
	background: #6a5cff;
}

.person .legs {
	position: absolute;
	bottom: 0;
	left: 2px;
	width: 10px;
	height: 6px;
	background: linear-gradient(
		to right,
		#222 0 4px,
		transparent 4px 6px,
		#222 6px 10px
	);
}

.sign {
	position: absolute;
	left: 50%;
	top: calc(50% - 92px);
	transform: translateX(-50%);
	width: 84px;
	height: 30px;
	background: #1d1d1d;
	border: 4px solid #f1f1f1;
	color: #f1f1f1;
	font-size: 10px;
	display: flex;
	align-items: center;
	justify-content: center;
	z-index: 8;
	letter-spacing: 1px;
}

.sign::after {
	content: "";
	position: absolute;
	left: 50%;
	top: 100%;
	transform: translateX(-50%);
	width: 6px;
	height: 22px;
	background: #d9d9d9;
}

.hud {
	position: absolute;
	left: 16px;
	top: 16px;
	padding: 8px 10px;
	background: rgba(0, 0, 0, 0.75);
	color: #fff;
	border: 3px solid #fff;
	z-index: 20;
	font-size: 12px;
	line-height: 1.4;
	text-transform: uppercase;
}

.shadow {
	position: absolute;
	inset: 0;
	background: linear-gradient(
		to bottom,
		rgba(255, 255, 255, 0.04),
		transparent 16%,
		transparent 84%,
		rgba(0, 0, 0, 0.08)
	);
	pointer-events: none;
	z-index: 30;
}
